SELECT COUNT(id) 
FROM browser 
WHERE market_share >= 0.05;

SELECT DISTINCT c.Location 
FROM cinema c 
WHERE c.Capacity <= 800;

SELECT COUNT(Member_ID) AS Number_of_Members_with_Black_Card
FROM member
WHERE Membership_card = 'black';

SELECT DISTINCT T1.Dname 
FROM department AS T1 
ORDER BY T1.Mgr_start_date;

SELECT COUNT(head_ID) 
FROM head 
WHERE age > 56;

SELECT COUNT(*) 
FROM flight 
WHERE Velocity > 200;

SELECT COUNT(id) AS Games_Held_After_2007
FROM game
WHERE Season > '2007';

SELECT DISTINCT cmi_details 
FROM Customer_Master_Index 
WHERE master_customer_id IN (
    SELECT master_customer_id FROM CMI_Cross_References WHERE source_system_code = 'Tax'
);

SELECT state_name 
FROM highlow 
ORDER BY highest_elevation DESC LIMIT 1;

SELECT COUNT(state_name) AS num_states_bordering_largest_state
FROM state s1
WHERE s1.state_name IN (
    SELECT b.border FROM border_info b
    WHERE b.state_name = (SELECT MAX(state_name) FROM state)
);

SELECT COUNT(state_name) AS num_states_bordering_Hawaii
FROM border_info
WHERE border = 'Hawaii';

SELECT COUNT(DISTINCT T1.state_name) AS num_states_next_to_rivers
FROM state AS T1
JOIN river AS T2 ON T1.state_name = T2.traverse;

SELECT DISTINCT state_name 
FROM state 
WHERE state_name != 'Texas';

SELECT MAX(population) AS largest_population, state_name 
FROM state 
GROUP BY state_name;

SELECT MIN(state_name) AS smallest_state
FROM state
WHERE state_name IN (
    SELECT state_name FROM border_info WHERE border = 'Texas'
);

SELECT state_name 
FROM state 
ORDER BY area ASC LIMIT 1;

SELECT COUNT(river_name) AS number_of_rivers
FROM river
WHERE traverse = 'Albany';

SELECT state_name 
FROM state 
WHERE population = (SELECT MAX(population) FROM city);

SELECT COUNT(state_name) AS number_of_states_without_rivers
FROM state
WHERE state_name NOT IN (SELECT state_name FROM river);
